    useEffect(() => {
        // Animasi Background menggunakan GSAP
        gsap.to(".bg-batik-top", {
            scale: 1.05,
            rotation: 1.5,
            xPercent: -2,
            yPercent: 2,
            duration: 15,
            ease: "sine.inOut",
            repeat: -1,
            yoyo: true
        });

        gsap.to(".bg-batik-bottom", {
            scale: 1.05,
            rotation: -1.5,
            xPercent: 2,
            yPercent: -2,
            duration: 15,
            ease: "sine.inOut",
            repeat: -1,
            yoyo: true
        });

        // Intersection Observer untuk elemen reveal
        const reveals = document.querySelectorAll(".reveal");
        const observer = new IntersectionObserver((entries) => {
            entries.forEach(entry => {
                if (entry.isIntersecting) {
                    entry.target.classList.add("active");
                }
            });
        }, { threshold: 0.1 });

        reveals.forEach(reveal => {
            observer.observe(reveal);
        });

        return () => {
            observer.disconnect();
            gsap.killTweensOf(".bg-batik-top");
            gsap.killTweensOf(".bg-batik-bottom");
        };
    }, []);

    // Fungsi klik pin peta yang disinkronkan agar carousel ter-reset sempurna
    const handlePinClick = (data: BatikData | undefined) => {
        if (!data || data.id === activeBatik.id) return;
        setIsFading(true);
        setTimeout(() => {
            setActiveBatik(data);
            setActiveMotifIndex(0); // Reset indeks ke motif pertama
            setSelectedMotif(data.motifs[0]); // Reset objek ke motif pertama daerah baru
            setIsFading(false);
        }, 300);
    };
