    const getPathProps = (svgId: string) => {
        // Cari apakah SVG ID ini ada di database kita
        const matchingBatik = batikDatabase.find(b => b.svgIds.includes(svgId));
        const isActive = activeBatik.svgIds.includes(svgId);

        if (matchingBatik) {
            // Jika provinsi ADA di database (bisa diklik)
            return {
                onClick: () => handlePinClick(matchingBatik),
                className: `cursor-pointer transition-colors duration-300 stroke-surface-white stroke-[0.5px] outline-none ${isActive ? 'fill-indigo-blue' : 'fill-surface-variant hover:fill-soga-brown'
                    }`
            };
        }

        // Jika provinsi TIDAK ADA di database (tidak bisa diklik)
        return {
            className: "fill-surface-dim stroke-surface-white stroke-[0.5px] opacity-50 outline-none"
        };
    };
    // Di dalam komponen Home:
    const [activeMotifIndex, setActiveMotifIndex] = useState(0); // Tambahkan state ini

    // Saat menampilkan di Panel Detail:
    const currentMotif = activeBatik.motifs[activeMotifIndex];

